/**
 * Adeptra Merchant — WooCommerce MCP Shopping Server.
 *
 * Implements UCP's canonical catalog + cart tool surface (search_catalog,
 * lookup_catalog, get_product, create_cart, get_cart, update_cart,
 * cancel_cart — see mcpTools.ts) against WooCommerce's Store API. HARD
 * BOUNDARY: this server never processes payment. The cart's continue_url
 * hands off to this store's own checkout page — no /wc/store/v1/checkout
 * call, no /wc/v3/ (admin) call, anywhere in this file or woocommerce.ts.
 * See README.md's "About UCP protocol conformance" section for exactly
 * what is and isn't UCP-conformant here.
 */

import "./loadEnv.js"; // MUST be the first import — see loadEnv.ts's header

import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { registerUcpTools } from "./mcpTools.js";
import { searchProducts, getProduct, getCartRaw, addItem, setItemQty, removeItem, emptyCart, checkoutUrl } from "./woocommerce.js";

if (!process.env.WOOCOMMERCE_STORE_URL) {
  console.error("Set WOOCOMMERCE_STORE_URL in .env (see .env.example) before starting this server.");
  process.exit(1);
}

const server = new McpServer({ name: "woocommerce-shopping-server", version: "1.0.0" });

registerUcpTools(server, {
  catalog: { searchProducts, getProduct },
  cart: { getCartRaw, addItem, setItemQty, removeItem, emptyCart, checkoutUrl },
});

const transport = new StdioServerTransport();
await server.connect(transport);
console.error("WooCommerce MCP shopping server running (stdio).");

