/**
 * Thin WooCommerce Store API client. Catalog reads + cart building ONLY —
 * this file never calls /wc/store/v1/checkout (payment) or any /wc/v3/
 * (admin) route. Exports the primitive functions registerUcpTools (see
 * mcpTools.ts) wires up as this platform's CatalogPrimitives/CartPrimitives
 * — every function here returns NORMALIZED shapes (NormalizedProduct /
 * NormalizedCart), not WooCommerce's own raw REST response shape.
 *
 * Cart state persists across calls via the Cart-Token header (the documented
 * headless pattern): the first cart-touching request returns a Cart-Token
 * response header, cached here in memory and replayed on every subsequent
 * call. When using Cart-Token, no separate nonce is required.
 *
 * One in-memory cart token per running process — this scaffold assumes one
 * server process serves one shopper session at a time (the typical MCP
 * stdio deployment model: one process per connected agent session). A
 * multi-shopper deployment would need a per-session token store instead.
 */

import type { NormalizedProduct, NormalizedCart } from "./mcpTools.js";

const STORE_URL = process.env.WOOCOMMERCE_STORE_URL;
const CHECKOUT_PATH = process.env.WOOCOMMERCE_CHECKOUT_PATH || "/checkout/";

// NOT enforced at module load — server.ts's own top-level check (before it
// imports anything that calls these) is what produces the clean "set your
// env vars" message. A throw here at import time would win the race
// against that check every time (imports evaluate before the importing
// module's own body runs) and surface as an ugly uncaught exception
// instead. assertStoreUrl(), called at the point of use, is defense-in-
// depth for anyone importing this file directly.
function assertStoreUrl(): string {
  if (!STORE_URL) throw new Error("Set WOOCOMMERCE_STORE_URL in .env (see .env.example).");
  return STORE_URL;
}

let cartToken: string | null = null;

async function storeApiFetch(path: string, init: RequestInit = {}): Promise<any> {
  const base = `${assertStoreUrl().replace(/\/+$/, "")}/wp-json/wc/store/v1`;
  const headers: Record<string, string> = {
    "content-type": "application/json",
    ...(init.headers as Record<string, string> | undefined),
  };
  if (cartToken) headers["Cart-Token"] = cartToken;

  const res = await fetch(`${base}${path}`, { ...init, headers });
  const token = res.headers.get("Cart-Token");
  if (token) cartToken = token;

  const text = await res.text();
  if (!res.ok) {
    throw new Error(`WooCommerce Store API ${init.method ?? "GET"} ${path} -> ${res.status}: ${text}`);
  }
  return text ? JSON.parse(text) : null;
}

interface RawProduct {
  id: number;
  name: string;
  permalink: string;
  prices: { price: string; currency_code: string };
}

function toNormalizedProduct(p: RawProduct): NormalizedProduct {
  return { id: String(p.id), title: p.name, price: p.prices?.price, currency: p.prices?.currency_code, url: p.permalink };
}

export async function searchProducts(query: string, limit: number): Promise<NormalizedProduct[]> {
  const q = new URLSearchParams({ search: query, per_page: String(limit) });
  const raw: RawProduct[] = await storeApiFetch(`/products?${q.toString()}`);
  return raw.map(toNormalizedProduct);
}

export async function getProduct(id: string): Promise<NormalizedProduct> {
  const raw: RawProduct = await storeApiFetch(`/products/${id}`);
  return toNormalizedProduct(raw);
}

interface RawCartItem {
  key: string;
  id: number;
  name: string;
  quantity: number;
  prices: { price: string };
}

interface RawCart {
  items: RawCartItem[];
}

function toNormalizedCart(raw: RawCart): NormalizedCart {
  return {
    lines: raw.items.map((i) => ({ id: i.key, productId: String(i.id), quantity: i.quantity, title: i.name, price: i.prices?.price })),
  };
}

export async function getCartRaw(): Promise<NormalizedCart> {
  const raw: RawCart = await storeApiFetch("/cart");
  return toNormalizedCart(raw);
}

export async function addItem(productId: string, quantity: number): Promise<void> {
  await storeApiFetch("/cart/add-item", { method: "POST", body: JSON.stringify({ id: Number(productId), quantity }) });
}

export async function setItemQty(lineItemId: string, quantity: number): Promise<void> {
  await storeApiFetch("/cart/update-item", { method: "POST", body: JSON.stringify({ key: lineItemId, quantity }) });
}

export async function removeItem(lineItemId: string): Promise<void> {
  await storeApiFetch("/cart/remove-item", { method: "POST", body: JSON.stringify({ key: lineItemId }) });
}

/** No bulk-clear endpoint is used here — built from the already-verified
 *  single-item removeItem() instead of assuming an unverified bulk-clear
 *  route exists on every WooCommerce Store API installation. */
export async function emptyCart(): Promise<void> {
  const cart = await getCartRaw();
  for (const line of cart.lines) {
    await removeItem(line.id);
  }
}

/** A static computed URL — no API call needed, this platform's checkout
 *  page is always at a known path. */
export async function checkoutUrl(): Promise<string> {
  return `${assertStoreUrl().replace(/\/+$/, "")}${CHECKOUT_PATH}`;
}
